DECLARE
  VCONSTRAINT USER_INDEXES.INDEX_NAME%TYPE;
  CURSOR C_CONSTRAINTS(PCONSTRAINT VARCHAR2) IS
    SELECT A.CONSTRAINT_NAME, A.TABLE_NAME
      FROM USER_CONSTRAINTS A
     WHERE A.TABLE_NAME = 'PCMENSAGEMMDFE'
       AND A.CONSTRAINT_NAME = PCONSTRAINT 
       AND A.INDEX_NAME IS NOT NULL;  
       
  CURSOR C_INDEXES IS
    SELECT A.INDEX_NAME, COUNT(B.COLUMN_NAME) QTDECOLUMN
      FROM USER_INDEXES A
         , USER_IND_COLUMNS B
     WHERE A.TABLE_NAME = 'PCMENSAGEMMDFE'
       AND A.INDEX_NAME = B.INDEX_NAME
       AND A.TABLE_NAME = B.TABLE_NAME
       AND A.INDEX_TYPE = 'NORMAL'
  GROUP BY A.INDEX_NAME;
BEGIN
  EXECUTE IMMEDIATE 'TRUNCATE TABLE PCMENSAGEMMDFE';
   
  FOR C IN C_INDEXES LOOP
    IF C.QTDECOLUMN <> 2 THEN
      VCONSTRAINT := C.INDEX_NAME;
      FOR C IN C_CONSTRAINTS(VCONSTRAINT) LOOP
        BEGIN
          EXECUTE IMMEDIATE 'ALTER TABLE ' || C.TABLE_NAME || ' DROP CONSTRAINT ' || C.CONSTRAINT_NAME;
        EXCEPTION
          WHEN OTHERS THEN
            NULL;
        END;    
      END LOOP;   
             
      BEGIN
        EXECUTE IMMEDIATE 'DROP INDEX ' || C.INDEX_NAME;
      EXCEPTION
        WHEN OTHERS THEN
          NULL;
      END;
    END IF;    
  END LOOP;
        
  BEGIN
    EXECUTE IMMEDIATE 'ALTER TABLE PCMENSAGEMMDFE MODIFY REJEICAOSEFAZ VARCHAR2(1) NOT NULL';
  EXCEPTION
    WHEN OTHERS THEN
      NULL;
  END;
      
  BEGIN
    EXECUTE IMMEDIATE 'ALTER TABLE PCMENSAGEMMDFE ADD CONSTRAINT PCMENSAGEMMDFE_PK PRIMARY KEY (CODMENSAGEM, REJEICAOSEFAZ) USING INDEX TABLESPACE TS_INDICE';        
