    SELECT 716 COD, 'REJEICAO: SE MODAL RODOVIÁRIO E INFORMADO GRUPO DO CIOT(INFCIOT): REJEITAR SE O CPF/CNPJ DO RESPONSÁVEL PELA GERAÇÃO DO CIOT INFORMADO ESTIVER INVÁLIDO' DESCRICAO, 'S' REJEICAOSEFAZ FROM DUAL UNION
