    SELECT 1022 COD, 'QUANTIDADE MAXIMA DE 06 CARACTERES PERMITIDOS PARA A TARA DO VEICULO DE REBOQUE' DESCRICAO, 'N' REJEICAOSEFAZ FROM DUAL UNION
